css:
.loader {
  display: inline-flex;
  gap: 8px;
  color: #6366f1;
}
.loader i {
  width: 18px;
  height: 18px;
  border-radius: 7px;
  background: currentColor;
  opacity: 0.25;
  animation: step 1.2s ease-in-out infinite;
}
.loader i:nth-child(2) { animation-delay: 0.15s; }
.loader i:nth-child(3) { animation-delay: 0.3s; }
.loader i:nth-child(4) { animation-delay: 0.45s; }
@keyframes step {
  0%, 100% { opacity: 0.22; transform: translateY(0); }
  45% { opacity: 1; transform: translateY(-6px); }
}
